**APP Mass Calculation (Current)**:
```typescript
const PROCESSING_FEE = 5;
const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = { sword: 100, amulet: 60 };
type Item = { type: string };
type Scenario = { steps: { items: Item[] }[] };

const basePremiumFor = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

export const processScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const items = scenario.steps[0].items;
  const itemsBase = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
  return { results: [{ premium: itemsBase + PROCESSING_FEE }] };
};
```

- Constants: 5, 100, 60, 0, 0 = 5 × 1 = 5
- Bindings: PROCESSING_FEE, BASE_PREMIUM_BY_ITEM_TYPE, basePremiumFor, item, processScenario, input, scenario, items, itemsBase, sum, item (in reduce) = 11 × 1 = 11
- Invocations: reduce, basePremiumFor, +, +, ?? = 5 × 2 = 10
- Conditionals: 0
- Loops: 1 (reduce) × 5 = 5
- Assignments: 0

